create table dirkspzm32.aps_plan_op_a_mat_relation (
    sid                     varchar2(2 char) default '01' not null enable,
    firma_nr                number(2, 0) default 1 not null enable,
    aps_plan_status         varchar2(3 char) not null enable,
    aps_plan_auftrag_nr     number(*, 0) not null enable,
    aps_plan_ag             number(*, 0) not null enable,
    aps_plan_ag_upos        number(*, 0) not null enable,
    activity_id             number(*, 0) not null enable,
    materialrelation_type   number not null enable,
    child_id                varchar2(4000 char) not null enable,
    child_plan_ag           number(*, 0) not null enable,
    child_plan_ag_upos      number(*, 0) not null enable,
    child_activity_id       number(*, 0) not null enable,
    child_artikel_id        number(*, 0),
    child_lte_id            varchar2(20 char),
    child_auf_id            number(*, 0),
    fixed                   number,
    info_date_availability  date,
    info_time_buffer        number,
    overlap_value           number,
    menge                   number(*, 3),
    erstell_datum           date default sysdate not null enable,
    bearb_datum             date,
    materialrelation_info   varchar2(1000 char),
    materialrelation_valide varchar2(1 char) default 'F' not null enable
);

alter table dirkspzm32.aps_plan_op_a_mat_relation
    add constraint aps_plan_op_a_mat_relation_typ
        check ( materialrelation_type in ( 0, 1, 2, 4, 8,
                                           16, 128, 256 ) ) enable;

alter table dirkspzm32.aps_plan_op_a_mat_relation
    add constraint pk_aps_plan_op_act_mat_rel
        primary key ( aps_plan_status,
                      aps_plan_auftrag_nr,
                      aps_plan_ag,
                      activity_id,
                      aps_plan_ag_upos,
                      materialrelation_type,
                      child_id,
                      child_plan_ag,
                      child_plan_ag_upos,
                      child_activity_id )
            using index enable;


